  ('elementary-f29af906-moex-00901', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲將耕地出租予乙，下列敘述何者正確？', '["乙縱經甲承諾而將耕地一部分轉租丙，乙丙之租賃契約無效", "乙非經甲承諾，將耕地一部分轉租丙，乙丙之租賃契約效力未定", "乙經甲承諾後，得將耕地全部轉租丙", "乙非經甲承諾，將耕地一部分轉租丙，甲得撤銷乙丙之租賃契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00902', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依農地重劃條例規定，下列有關農地重劃費用負擔之敘述，何者正確？', '["區域性排水工程由農田水利會興辦並負擔費用", "區域性排水工程由政府興辦並負擔費用", "區域性排水工程所需費用由政府與土地所有權人分擔", "區域性排水工程由土地所有權人興辦並分擔費用，分擔比例由行政院定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00903', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅減免規則之規定，經事業主管機關核准設立，對外絕對公開，並不以營利為目的之私立公園及 體育館場，其為財團法人組織所有者，關於其用地之地價稅，下列何者正確？', '["免徵", "減徵百分之四十", "減徵百分之五十", "減徵百分之七十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
